{
    uint16_t regValue;
    uint16_t statusBitShift;
    uint32_t regintValue;
    DCSM_EXEOnlyStatus status;

    //
    // Check if sector belongs to this zone
    //
    if(DCSM_getFlashSectorZone(sector) != DCSM_MEMORY_ZONE1)
    {
        status = DCSM_INCORRECT_ZONE;
    }
    else
    {
        //
        // Get the EXE status register
        //
        if(sector <= DCSM_SECTOR_15)
        {
            regintValue = ((HWREG(DCSM_Z1_BASE + DCSM_O_Z1_EXEONLYSECT1R)) &
                           DCSM_EXEONLYSECTR_M);
            statusBitShift = (uint16_t)sector;
            regValue = (uint16_t)regintValue;
        }
        else if(sector <= DCSM_SECTOR_31)
        {
            regintValue = ((HWREG(DCSM_Z1_BASE + DCSM_O_Z1_EXEONLYSECT1R))
                           >> DCSM_EXEONLYSECTR_S);

            regValue = (uint16_t)regintValue;
            statusBitShift = (uint16_t)sector & 0xFU;
        }
        else
        {
            regintValue = ((HWREG(DCSM_Z1_BASE + DCSM_O_Z1_EXEONLYSECT2R)) &
                           DCSM_EXEONLYSECTR_M);
            regValue = (uint16_t)regintValue;
            statusBitShift = (uint16_t)sector & 0xFU;
        }
        //
        // Get the EXE status of the Flash Sector
        //
        status = (DCSM_EXEOnlyStatus)(uint16_t)(((regValue >> statusBitShift) &
                                                 0x01U));
    }
    return(status);
}

